// src/pages/Transactions.jsx
// Lista de transacciones + formulario para agregar nuevas.

import { useState } from 'react'
import { useTransactions }  from '../hooks/useTransactions'
import { formatCurrency, formatDateShort } from '../utils/formatCurrency'
import Button from '../components/common/Button'
import styles from './Transactions.module.css'

const CATEGORIES = ['alimentación','transporte','vivienda','salud','entretenimiento','educación','ropa','otros']
const EMPTY_FORM = { type: 'expense', description: '', amount: '', category: 'alimentación', date: '', notes: '' }

const CATEGORY_EMOJI = {
  alimentación: '🛒', transporte: '🚗', vivienda: '🏠', salud: '💊',
  entretenimiento: '🎬', educación: '📚', ropa: '👕', otros: '📦',
}

export default function Transactions() {
  const { transactions, loading, error, addTransaction, removeTransaction } = useTransactions()
  const [form,    setForm]    = useState(EMPTY_FORM)
  const [saving,  setSaving]  = useState(false)
  const [formErr, setFormErr] = useState(null)
  const [success, setSuccess] = useState(false)

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value })
    setFormErr(null); setSuccess(false)
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    setSaving(true); setFormErr(null)
    try {
      await addTransaction({ ...form, amount: Number(form.amount) })
      setForm(EMPTY_FORM)
      setSuccess(true)
    } catch (err) {
      setFormErr(err.response?.data?.error || 'Error al guardar')
    } finally {
      setSaving(false)
    }
  }

  return (
    <div className={styles.page}>
      <h1 className={styles.title}>Transacciones</h1>

      <div className={styles.layout}>
        {/* ── Formulario ───────────────────────────── */}
        <div className="card">
          <p className="card-title">Nueva transacción</p>
          <form onSubmit={handleSubmit} className={styles.form}>

            {/* Tipo */}
            <div className={styles.typeToggle}>
              {['expense','income'].map((t) => (
                <button
                  key={t} type="button"
                  className={`${styles.typeBtn} ${form.type === t ? styles.typeActive : ''} ${t === 'income' ? styles.incomeBtn : ''}`}
                  onClick={() => setForm({ ...form, type: t })}
                >
                  {t === 'expense' ? '🔴 Gasto' : '💚 Ingreso'}
                </button>
              ))}
            </div>

            <div className="form-group">
              <label>Descripción</label>
              <input name="description" placeholder="Ej: Mercado" value={form.description} onChange={handleChange} required />
            </div>
            <div className="form-row">
              <div className="form-group">
                <label>Monto ($)</label>
                <input name="amount" type="number" min="1" placeholder="0" value={form.amount} onChange={handleChange} required />
              </div>
              <div className="form-group">
                <label>Categoría</label>
                <select name="category" value={form.category} onChange={handleChange}>
                  {CATEGORIES.map((c) => (
                    <option key={c} value={c}>{CATEGORY_EMOJI[c]} {c.charAt(0).toUpperCase() + c.slice(1)}</option>
                  ))}
                </select>
              </div>
            </div>
            <div className="form-row">
              <div className="form-group">
                <label>Fecha (opcional)</label>
                <input name="date" type="date" value={form.date} onChange={handleChange} />
              </div>
              <div className="form-group">
                <label>Notas (opcional)</label>
                <input name="notes" placeholder="Notas..." value={form.notes} onChange={handleChange} />
              </div>
            </div>

            {formErr && <p className="msg msg--error">{formErr}</p>}
            {success  && <p className="msg msg--success">✅ Guardado correctamente</p>}

            <Button type="submit" fullWidth loading={saving}>Guardar transacción</Button>
          </form>
        </div>

        {/* ── Lista ────────────────────────────────── */}
        <div className="card">
          <p className="card-title">Historial ({transactions.length})</p>
          {loading && <p style={{ color: 'var(--text-2)' }}>Cargando...</p>}
          {error   && <p className="msg msg--error">{error}</p>}
          {!loading && transactions.length === 0 && (
            <p style={{ color: 'var(--text-2)', fontSize: '0.9rem' }}>Sin transacciones aún.</p>
          )}
          <ul className={styles.list}>
            {transactions.map((t) => (
              <li key={t.id} className={styles.item}>
                <span className={styles.emoji}>{CATEGORY_EMOJI[t.category] || '📦'}</span>
                <div className={styles.info}>
                  <p className={styles.desc}>{t.description}</p>
                  <p className={styles.meta}>{t.category} · {formatDateShort(t.date)}</p>
                </div>
                <span className={t.type === 'income' ? styles.pos : styles.neg}>
                  {t.type === 'income' ? '+' : '-'}{formatCurrency(t.amount)}
                </span>
                <button className={styles.del} onClick={() => removeTransaction(t.id)} title="Eliminar">✕</button>
              </li>
            ))}
          </ul>
        </div>
      </div>
    </div>
  )
}
